/** UsptMsvcDao.save */
insert into uspt_msvc
	(
		member_id
		, msvc_type_cd
		, msvc_bgnde
		, msvc_endde
		, msvc_exempt_reason
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{memberId}
		, #{msvcTypeCd}
		, #{msvcBgnde}
		, #{msvcEndde}
		, #{msvcExemptReason}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	) on conflict (member_id)
	do update
	set msvc_type_cd	= #{msvcTypeCd}
		, msvc_bgnde	= #{msvcBgnde}
		, msvc_endde	= #{msvcEndde}
		, msvc_exempt_reason	= #{msvcExemptReason}
		, updater_id	= #{updaterId}
		, updated_dt	= #{updatedDt}
